const closing = $('Capital Recovery Webhook').first().json;
const commitments = $('Fetch Deal Commitments').first().json.commitments || [];
const totalCommitted = commitments.reduce((s, c) => s + (c.amount || 0), 0);
const distributions = commitments.map(c => {
  const share = totalCommitted > 0 ? c.amount / totalCommitted : 0;
  const preferredReturn = c.amount * (c.investors?.preferred_return || 0.08);
  const profitShare = Math.max(0, closing.net_profit - (totalCommitted * 0.08)) * share * 0.50;
  const total = c.amount + preferredReturn + profitShare;
  return {
    investor_id: c.investor_id,
    deal_id: closing.deal_id || closing.property_id,
    amount: Math.round(total * 100) / 100,
    distribution_date: closing.close_date,
    type: 'Return of Capital',
    status: 'Pending'
  };
});
return distributions.map(d => ({ json: d }));

